import { revalidateTag } from 'next/cache';
import { getAllProducts } from '@/lib/db';
import { SyncCatalogButton } from './_components/SyncCatalogButton';

/**
 * Cached catalog fetch — tagged with "products".
 *
 * Because the result is cached, every-day browsing (read-heavy) never
 * re-queries the upstream data source.  Invalidating the tag (e.g. via
 * a sync action) causes the *next* render to fetch fresh data while the
 * current request still serves the stale snapshot — eventual consistency
 * without blocking operators.
 */
const getCachedCatalog = unstable_cache(
  async () => {
    const products = await getAllProducts();
    return { products, syncedAt: Date.now() };
  },
  ['admin-catalog-products'],
  { tags: ['products'] },
);

function formatTime(ts: number) {
  return Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'medium',
  }).format(ts);
}

export default async function AdminPage() {
  const { products, syncedAt } = await getCachedCatalog();

  async function syncCatalog() {
    'use server';

    // Invalidate every cache entry tagged with "products".
    // The current render still serves the stale snapshot; the next
    // render re-executes getCachedCatalog and picks up fresh data.
    revalidateTag('products');
  }

  return (
    <div style={pageStyle}>
      <header style={headerStyle}>
        <div>
          <h1 style={titleStyle}>Product Catalog</h1>
          <p style={subtitleStyle}>
            Last synced: {formatTime(syncedAt)}
          </p>
        </div>

        <form action={syncCatalog}>
          <SyncCatalogButton />
        </form>
      </header>

      {products.length > 0 ? (
        <div style={{ overflowX: 'auto' }}>
          <table style={tableStyle}>
            <thead>
              <tr style={{ backgroundColor: '#f5f5f5', textAlign: 'left' }}>
                <th style={thStyle}>ID</th>
                <th style={thStyle}>Name</th>
                <th style={thStyle}>Category</th>
                <th style={{ ...thStyle, textAlign: 'right' }}>Price</th>
                <th style={{ ...thStyle, textAlign: 'right' }}>Inventory</th>
                <th style={thStyle}>Status</th>
              </tr>
            </thead>
            <tbody>
              {products.map((product) => (
                <tr key={product.id} style={rowStyle}>
                  <td style={tdStyle}>{product.id}</td>
                  <td style={tdStyle}>{product.name}</td>
                  <td style={tdStyle}>{product.category}</td>
                  <td style={{ ...tdStyle, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                    ${product.price.toFixed(2)}
                  </td>
                  <td style={{ ...tdStyle, textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                    {product.inventory}
                  </td>
                  <td style={tdStyle}>
                    {product.status === 'discontinued' ? (
                      <span style={discontinuedStyle}>Discontinued</span>
                    ) : (
                      <span style={activeStyle}>Active</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <p style={{ color: '#888' }}>No products found.</p>
      )}

      <p style={footerStyle}>
        {products.length} product{products.length !== 1 ? 's' : ''}
      </p>
    </div>
  );
}

